 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { getName } from '@kubevirt-utils/resources/shared';
 5	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Checkbox, StackItem } from '@patternfly/react-core';
 7	
 8	import { sameResource } from '../utils/helpers';
 9	
10	type DeleteResourceCheckboxProps = {
11	  resource: K8sResourceCommon;
12	
13	  resourcesToSave: K8sResourceCommon[];
14	  setResourcesToSave: Dispatch<SetStateAction<K8sResourceCommon[]>>;
15	};
16	
17	const DeleteResourceCheckbox: FC<DeleteResourceCheckboxProps> = ({
18	  resource,
19	  resourcesToSave,
20	  setResourcesToSave,
21	}) => {
22	  const { t } = useKubevirtTranslation();
23	  const resourceName = getName(resource);
24	
25	  const saveResource = () => setResourcesToSave((prevVolumes) => [...prevVolumes, resource]);
26	
27	  const deleteResource = () =>
28	    setResourcesToSave((prevVolumes) =>
29	      prevVolumes.filter((volume) => !sameResource(volume, resource)),
30	    );
31	
32	  return (
33	    <StackItem>
34	      <Checkbox
35	        label={t('Delete disk {{resourceName}} ({{kindAbbr}})', {
36	          kindAbbr: resource.kind,
37	          resourceName,
38	        })}
39	        id={`${resource.kind}-${resourceName}`}
40	        isChecked={!resourcesToSave.find((volume) => sameResource(volume, resource))}
41	        onChange={(_, checked: boolean) => (checked ? deleteResource() : saveResource())}
42	      />
43	    </StackItem>
44	  );
45	};
46	
47	export default DeleteResourceCheckbox;

